solution_code:
#include <stdio.h>

int deref_int(int *p) {
    return *p;
}

int sum_array_ptr(int *arr, int n) {
    int sum = 0;
    for (int *p = arr; p < arr + n; p++) {
        sum += *p;
    }
    return sum;
}

void swap_int(int *a, int *b) {
    int tmp = *a;
    *a = *b;
    *b = tmp;
}

validation.test_code:
void test_deref_int(void) {
    int x = 42;
    TEST_ASSERT_EQUAL_INT(42, deref_int(&x));
    x = -7;
    TEST_ASSERT_EQUAL_INT(-7, deref_int(&x));
    int zero = 0;
    TEST_ASSERT_EQUAL_INT(0, deref_int(&zero));
}

void test_sum_array_ptr(void) {
    int arr1[] = {1, 2, 3, 4, 5};
    TEST_ASSERT_EQUAL_INT(15, sum_array_ptr(arr1, 5));
    int arr2[] = {0};
    TEST_ASSERT_EQUAL_INT(0, sum_array_ptr(arr2, 1));
    int arr3[] = {-3, 7};
    TEST_ASSERT_EQUAL_INT(4, sum_array_ptr(arr3, 2));
    int arr4[] = {10, -10};
    TEST_ASSERT_EQUAL_INT(0, sum_array_ptr(arr4, 2));
}

void test_swap_int(void) {
    int a = 10, b = 20;
    swap_int(&a, &b);
    TEST_ASSERT_EQUAL_INT(20, a);
    TEST_ASSERT_EQUAL_INT(10, b);
    int x = 0, y = 0;
    swap_int(&x, &y);
    TEST_ASSERT_EQUAL_INT(0, x);
    TEST_ASSERT_EQUAL_INT(0, y);
}

int main(void) {
    UNITY_BEGIN();
    RUN_TEST(test_deref_int);
    RUN_TEST(test_sum_array_ptr);
    RUN_TEST(test_swap_int);
    return UNITY_END();
}
